#include<bits/stdc++.h>
using namespace std;
bool flagl[200010],flagr[200010];
int l[200010],r[200010];
int flag[200010];
int main()
{
    int n,m,x;
    scanf("%d%d%d",&n,&m,&x);
    vector<int> ans;
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&l[i],&r[i]);
        flag[l[i]]++;
        flag[r[i]+1]--;
        flagl[l[i]]=true;
        flagr[r[i]]=true;
    }
    for(int i=1;i<=n;i++)
    {
        flag[i]+=flag[i-1];
    }
    flagl[x]=flagr[x]=0;
    for(int i=x;i>=1;i--)
    {
        if(!flag[i])
        {
            break;
        }
        if(flagl[i])
        {
            ans.push_back(i);
        }
    }
    for(int i=x;i<=n;i++)
    {
        if(!flag[i])
        {
            break;
        }
        if(flagr[i])
        {
            ans.push_back(i);
        }
    }
    sort(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d ",i);
    }
    return 0;
}
